#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compareVersion(char * version1, char * version2) {
    int i = 0, j = 0;
    int v1 = 0, v2 = 0;
    while (version1[i] || version2[j]) {
        while (version1[i] && version1[i] != '.') {
            v1 = v1 * 10 + version1[i++] - '0';
        }
        while (version2[j] && version2[j] != '.') {
            v2 = v2 * 10 + version2[j++] - '0';
        }
        if (v1 > v2) return 1;
        if (v1 < v2) return -1;
        v1 = 0; v2 = 0;
        if (version1[i]) i++;
        if (version2[j]) j++;
    }
    return 0;
}

